def threeSum(nums: list[int]) -> list[list[int]]:
    n = len(nums)
    if n < 3:
        return []

    nums.sort()
    res = []

    for i in range(n - 2):
        # 剪枝：最小的数大于0，无法组成和为0的三元组
        if nums[i] > 0:
            break

        # 去重：跳过重复的第一个数
        if i > 0 and nums[i] == nums[i - 1]:
            continue

        left, right = i + 1, n - 1
        while left < right:
            total = nums[i] + nums[left] + nums[right]
            if total == 0:
                res.append([nums[i], nums[left], nums[right]])
                # 去重：跳过重复的第二个数
                while left < right and nums[left] == nums[left + 1]:
                    left += 1
                # 去重：跳过重复的第三个数
                while left < right and nums[right] == nums[right - 1]:
                    right -= 1
                left += 1
                right -= 1
            elif total < 0:
                left += 1
            else:
                right -= 1

    return res
